import React from 'react';
import Iframe from 'react-iframe'

function VideoCard({ url }) {
  return (
    <div className="videoCardPlayer">
    <Iframe url={url}
            position="absolute"
            width="100%"
            id="myId"
            className="myClassname"
            height="100%"
            styles={{height: "25px"}}/>
    </div>
  );
}

export default VideoCard;
